// Pipeline script for Node.js CI/CD
const { exec } = require('child_process');

exec('npm install', (err, stdout, stderr) => {
  if (err) {
    console.error(`Error occurred during dependency installation: ${err}`);
    return;
  }

  exec('npm run test', (err, stdout, stderr) => {
    if (err) {
      console.error(`Error occurred during tests execution: ${err}`);
      return;
    }

    exec('npm run build', (err, stdout, stderr) => {
      if (err) {
        console.error(`Error occurred during application building: ${err}`);
        return;
      }

      exec('npm run deploy', (err, stdout, stderr) => {
        if (err) {
          console.error(`Error occurred during deployment: ${err}`);
          return;
        }

        console.log('Application deployed successfully!');
      });
    });
  });
});